def test_generate_per_frame_sheet_full_scale_canvas(tmp_path):
    """Regression test: canvas_w must include the crops row width at full scale.

    At default crop_size=400 with 11 cells, crops row (4532 px) is wider than
    the thumbs row (~3432 px). Previously canvas_w was only max(gold, thumbs),
    so the rightmost crops got silently clipped. This test verifies the right
    edge isn't truncated by checking the final canvas has pixels in the last
    (rightmost) crop column's expected location.
    """
    # 9-method benchmark shape: orig_proxy + gold + 9 core methods (bilinear
    # baseline + 7 core + sr_realesrgan) = 11 total cells
    method_order = ["bilinear", "bicubic", "lanczos3", "joint_bilateral",
                    "guided_filter", "asymmetric_bilateral",
                    "higher_proxy", "sr_maxine", "sr_realesrgan"]
    method_finals = {name: torch.rand(1, 3, 200, 320, device="cuda", dtype=torch.float32)
                     for name in method_order}
    method_deltas = {name: torch.randn(1, 3, 200, 320, device="cuda", dtype=torch.float32) * 0.05
                     for name in method_order}
    method_metrics = {
        name: {"delta_l1": 0.01, "final_delta_e": 0.5, "final_delta_e_p95": 0.8, "ssim": 0.99}
        for name in method_order
    }
    out = tmp_path / "fullscale.png"
